mapper.select:
select c.notice_id as noticeId, c.id as targetId, case when c.notice_type=1 then 1 when c.notice_type=2 or c.notice_type=3 then 2 else c.notice_type end as noticeType, c.notice_title_i18n_code, c.message_content_i18n_code, c.target_type ,c.created_time as createdTime
,read_state as readState
from user_notice_target c left join agent_info ag on ag.agent_account=c.user_account
where c.target_type = 5 and c.delete_state=1 and c.agent_account = #{vo.agentAccount}
and c.notice_type = #{vo.noticeType}
and c.notice_type in(2,3)

select
    count(c.id)

from user_notice_config c, agent_info ag

where c.target_type = 3 and c.status=0 and ag.agent_account = #{agentAccount}
        and not exists (
            select t.notice_id
            from user_notice_target t
            where t.notice_id = c.id and t.user_account = #{agentAccount}
        )

    and c.notice_type = #{vo.noticeType}


    and c.notice_type in(2,3)

        and find_in_set(#{deviceTerminal}, c.send_object)


    and c.created_time  >=  ag.register_time

select
    count(c2.id)

from user_notice_target t2
         left join user_notice_config c2 on c2.id = t2.notice_id

where t2.user_id = #{agentId} and t2.revoke_state = 1 and t2.read_state = 0

                and t2.notice_type = #{noticeType}


                and t2.notice_type in(2,3)


    and c2.carousel_start_time   <=  #{currentTime}
    and c2.carousel_end_time   >=  #{currentTime}

            and t2.delete_state=1
